var version = "1.0.0"

func Execute() error {
	rootCmd := &cobra.Command{
		Use:          "profilepress",
		Short:        "Private LinkedIn profile change packets with privacy preflight",
		Long:         "profilepress snapshots a user's own LinkedIn profile, creates opportunity-specific change packets, diffs proposed edits, and blocks unsafe apply paths by default.",
		SilenceUsage: true,
		Version:      version,
	}
	rootCmd.SetVersionTemplate("profilepress {{ .Version }}\n")
	rootCmd.AddCommand(newSnapshotCmd())
	rootCmd.AddCommand(newPrivacyCheckCmd())
	rootCmd.AddCommand(newProposeForJobCmd())
	rootCmd.AddCommand(newDiffCmd())
	rootCmd.AddCommand(newApplyPacketCmd())
	rootCmd.AddCommand(newAuthCmd())
	rootCmd.AddCommand(newPacketCmd())
	rootCmd.AddCommand(newMessagesCmd())
	rootCmd.AddCommand(newDoctorCmd())
	rootCmd.AddCommand(newVersionCliCmd())
	return rootCmd.Execute()
}

func ExitCode(err error) int { return 1 }

func newVersionCliCmd() *cobra.Command {
	return &cobra.Command{Use: "version", Short: "Print version", Run: func(cmd *cobra.Command, args []string) { fmt.Printf("profilepress %s\n", version) }}
}
